            // Create a SchemaFactory instance for W3C XML Schema
            SchemaFactory schemaFactory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);

            // Convert the schema content string to an InputStream
            InputStream inputStream = new ByteArrayInputStream(schemaContent.getBytes("UTF-8"));

            // Compile the schema from the input stream
            this.loadedSchema = schemaFactory.newSchema(new javax.xml.transform.stream.StreamSource(inputStream));

        } catch (Exception e) {
            // Re-throw with additional context about the error
            throw new Exception("Failed to load XML Schema: " + e.getMessage(), e);
        }
    }

    // Getter for the loaded schema (useful for validation tasks)
    public Schema getLoadedSchema() {
        return loadedSchema;
    }
}
